    """
    Wrapper to keep the secondary dictionary, `_column_requires_decoding`, of the `Features` object
    in sync with the main dictionary.

    This is necessary because the two dictionaries need to be kept in sync for the `decode_example` method to work
    properly, and the `Features` class implements dict, and we want to keep the dict backend without switching to
    `UserDict` to avoid the performance/breaking changes it would imply, as `Features` is a very used class.

    Some methods of the `dict` class have to be re-defined using this wrapper.
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper._decorator_name_ = "_keep_dicts_synced"
    return wrapper


